from itertools import count
from sympy.ntheory import digits
def T(n, k): return next(m for m in count(1) if len(set(digits(m**k, n)[1:])) == k) if n>1 and k>1 else 1
def row(n): return [T(n, k) for k in range(1, n+1)]
print([e for n in range(1, 13) for e in row(n)]) # _Michael S. Branicky_, Jun 20 2026

